        elif pred == 'demonym':
            additional_info.append(f"demonym is {obj}")
        elif pred == 'isPartOf':
            location_clauses.append(f"part of {obj}")
        elif pred == 'birthPlace':
            additional_info.append(f"birth place is {obj}")
        elif pred == 'deathPlace':
            additional_info.append(f"death place is {obj}")
        elif pred == 'origin':
            additional_info.append(f"origin is {obj}")
        elif pred == 'significantBuilding':
            additional_info.append(f"significant building is {obj}")
        elif pred == 'significantProject':
            additional_info.append(f"significant project is {obj}")
        elif pred == 'foundationPlace':
            additional_info.append(f"foundation place is {obj}")
        elif pred == 'keyPerson':
            additional_info.append(f"key person is {obj}")
        elif pred == 'chancellor':
            additional_info.append(f"chancellor is {obj}")
        elif pred == 'capital':
            location_clauses.append(f"capital is {obj}")
        elif pred == 'cityServed':
            additional_info.append(f"serves the city of {obj}")

    # Process location-related triples from other subjects
    for t in triples:
        if t.subject != main_subject and t.predicate in ['country', 'capital', 'isPartOf']:
            related_info.append(f"{t.subject} {t.predicate.replace(' ', '')} {t.object}")

    # Build the main sentence
    if not main_parts:
        main_parts.append(f"{main_subject}")

    # Add location information
    if location_clauses:
        location_text = ", ".join(location_clauses)
        main_parts[0] += f", {location_text}"

    # Add additional building details
    if additional_info:
        details_text = ", ".join(additional_info)
        main_parts[0] += f", {details_text}"

    # Add related information
    if related_info:
        related_text = ", ".join(related_info)
        main_parts[0] += f", {related_text}"

    # Join everything and format properly
    sentence = main_parts[0]

    # Ensure proper capitalization and punctuation
    sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'

    return sentence

